// All-in-one: Validate Slack signature → Parse command → Check access → Execute → Return response
const crypto = require('crypto');
const https = require('https');
const { URL, URLSearchParams } = require('url');

// --- Helper: HTTPS request ---
function httpsRequest(url, method, hdrs, body) {
  return new Promise((resolve, reject) => {
    const urlObj = new URL(url);
    const bodyStr = body ? JSON.stringify(body) : null;
    const options = {
      hostname: urlObj.hostname,
      path: urlObj.pathname + urlObj.search,
      method,
      headers: {
        ...hdrs,
        ...(bodyStr ? { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } : {})
      }
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, data }));
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

// --- 1. Validate Slack Signature ---
const headers = $input.first().json.headers;
const rawBody = Buffer.from($input.first().binary.data.data, 'base64').toString('utf-8');
const signature = headers['x-slack-signature'];
const timestamp = headers['x-slack-request-timestamp'];
const signingSecret = $env.SLACK_SIGNING_SECRET;

if (!signingSecret) {
  return [{ json: { responseText: 'Error: SLACK_SIGNING_SECRET not configured' } }];
}

const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) {
  return [{ json: { responseText: 'Error: Request timestamp too old' } }];
}

const sigBasestring = `v0:${timestamp}:${rawBody}`;
const expected = 'v0=' + crypto.createHmac('sha256', signingSecret).update(sigBasestring).digest('hex');
if (!crypto.timingSafeEqual(Buffer.from(signature || ''), Buffer.from(expected))) {
  return [{ json: { responseText: 'Error: Invalid Slack signature' } }];
}

// --- 2. Parse Command ---
const params = new URLSearchParams(rawBody);
const text = (params.get('text') || '').trim();
const userId = params.get('user_id') || '';
const userName = params.get('user_name') || '';

const parts = text.split(/\s+/);
const command = (parts[0] || 'help').toLowerCase();
const arg = parts.slice(1).join(' ');

// --- 3. Check Access Tier ---
const adminUsers = ($env.SLACK_ADMIN_USERS || '').split(',').map(s => s.trim()).filter(Boolean);
const allowedUsers = ($env.SLACK_ALLOWED_USERS || '').split(',').map(s => s.trim()).filter(Boolean);

let tier = 'readonly';
if (adminUsers.length > 0 && adminUsers.includes(userId)) {
  tier = 'admin';
} else if (adminUsers.length === 0 && allowedUsers.length > 0 && allowedUsers.includes(userId)) {
  tier = 'admin';
} else if (allowedUsers.includes(userId)) {
  tier = 'allowed';
}
if (tier === 'readonly') {
  if (allowedUsers.length > 0) {
    return [{ json: { responseText: 'Error: Not authorized' } }];
  }
  tier = 'admin';
}

// --- 4. Route & Execute ---
const githubToken = $env.GITHUB_PAT;
const repo = 'stoa-platform/stoa';
const ghHeaders = {
  'Accept': 'application/vnd.github.v3+json',
  'Authorization': `token ${githubToken}`,
  'User-Agent': 'n8n-stoa-ai-factory'
};

let responseText = '';

try {
  if (command === 'help') {
    responseText = ':factory: */stoa* — AI Factory Commands\n\n' +
      '`/stoa help` — Show this help\n' +
      '`/stoa status` — Recent workflow runs\n' +
      '`/stoa queue` — Next 10 queued jobs\n' +
      '`/stoa queue stats` — Queue statistics\n' +
      '`/stoa queue pause` — Pause L3 pipeline (admin)\n' +
      '`/stoa queue resume` — Resume L3 pipeline (admin)\n' +
      '`/stoa scan` — Trigger backlog scan (admin)\n' +
      '`/stoa implement CAB-XXXX` — Dispatch ticket (admin)\n\n' +
      'Your tier: *' + tier + '*';

  } else if (command === 'status') {
    const result = await httpsRequest(
      'https://api.github.com/repos/' + repo + '/actions/runs?per_page=5&status=completed',
      'GET', ghHeaders, null
    );
    const runs = JSON.parse(result.data).workflow_runs || [];
    const lines = runs.map(r => {
      const emoji = r.conclusion === 'success' ? ':white_check_mark:' : ':x:';
      const date = new Date(r.updated_at).toISOString().slice(0, 16).replace('T', ' ');
      return emoji + ' *' + r.name + '* — ' + r.conclusion + ' (' + date + ')';
    });
    responseText = lines.length > 0
      ? ':satellite_antenna: *Recent Workflow Runs*\n' + lines.join('\n')
      : ':satellite_antenna: No recent workflow runs found.';

  } else if (command === 'scan') {
    if (tier !== 'admin') {
      responseText = 'Error: Scan requires admin tier';
    } else {
      await httpsRequest(
        'https://api.github.com/repos/' + repo + '/actions/workflows/claude-autopilot-scan.yml/dispatches',
        'POST', ghHeaders, { ref: 'main', inputs: { max_tickets: '3' } }
      );
      responseText = ':satellite_antenna: Backlog scan triggered. Results will appear in #ai-factory.';
    }

  } else if (command === 'implement') {
    if (tier !== 'admin') {
      responseText = 'Error: Implement requires admin tier';
    } else {
      const match = arg.match(/^(CAB-\d+)$/i);
      if (!match) {
        responseText = 'Error: Invalid ticket format. Expected: CAB-XXXX';
      } else {
        const ticketId = match[1].toUpperCase();
        await httpsRequest(
          'https://api.github.com/repos/' + repo + '/dispatches',
          'POST', ghHeaders, {
            event_type: 'linear-ticket-started',
            client_payload: {
              ticket_id: ticketId,
              ticket_title: 'Dispatched via /stoa',
              ticket_description: 'Triggered from Slack by ' + userName,
              priority: 2,
              estimate: 5
            }
          }
        );
        responseText = ':rocket: L3 pipeline dispatched for *' + ticketId + '*. Council will validate in #ai-factory.';
      }
    }

  } else if (command === 'queue') {
    const pbUrl = $env.HEGEMON_REMOTE_URL || '';
    const pbPass = $env.HEGEMON_REMOTE_PASSWORD || '';
    const subCmd = (parts[1] || '').toLowerCase();

    if (!pbUrl || !pbPass) {
      responseText = 'Error: HEGEMON_REMOTE_URL / HEGEMON_REMOTE_PASSWORD not configured';
    } else if (subCmd === 'pause') {
      if (tier !== 'admin') {
        responseText = 'Error: Queue pause requires admin tier';
      } else {
        try {
          await httpsRequest(
            'https://api.github.com/repos/' + repo + '/actions/variables/DISABLE_L3_LINEAR',
            'PATCH', ghHeaders, { name: 'DISABLE_L3_LINEAR', value: 'true' }
          );
        } catch (e) {
          await httpsRequest(
            'https://api.github.com/repos/' + repo + '/actions/variables',
            'POST', ghHeaders, { name: 'DISABLE_L3_LINEAR', value: 'true' }
          );
        }
        responseText = ':double_vertical_bar: L3 pipeline paused. Queue dispatch continues but no new Council runs.';
      }
    } else if (subCmd === 'resume') {
      if (tier !== 'admin') {
        responseText = 'Error: Queue resume requires admin tier';
      } else {
        await httpsRequest(
          'https://api.github.com/repos/' + repo + '/actions/variables/DISABLE_L3_LINEAR',
          'PATCH', ghHeaders, { name: 'DISABLE_L3_LINEAR', value: 'false' }
        );
        responseText = ':arrow_forward: L3 pipeline resumed.';
      }
    } else if (subCmd === 'stats') {
      const authRes = await httpsRequest(
        pbUrl + '/api/admins/auth-with-password',
        'POST', {}, { identity: 'admin@gostoa.dev', password: pbPass }
      );
      const pbToken = JSON.parse(authRes.data).token;
      const pbAuth = { 'Authorization': 'Bearer ' + pbToken };
      const pendRes = await httpsRequest(pbUrl + '/api/collections/queue_jobs/records?filter=(status=%27pending%27)&fields=id&perPage=1', 'GET', pbAuth, null);
      const dispRes = await httpsRequest(pbUrl + '/api/collections/queue_jobs/records?filter=(status=%27dispatched%27)&fields=id&perPage=1', 'GET', pbAuth, null);
      const doneRes = await httpsRequest(pbUrl + '/api/collections/queue_jobs/records?filter=(status=%27done%27)&fields=id&perPage=1', 'GET', pbAuth, null);
      const failRes = await httpsRequest(pbUrl + '/api/collections/queue_jobs/records?filter=(status=%27failed%27)&fields=id&perPage=1', 'GET', pbAuth, null);
      const pend = JSON.parse(pendRes.data).totalItems || 0;
      const disp = JSON.parse(dispRes.data).totalItems || 0;
      const done = JSON.parse(doneRes.data).totalItems || 0;
      const fail = JSON.parse(failRes.data).totalItems || 0;
      responseText = ':bar_chart: *Queue Stats*\n' +
        ':hourglass_flowing_sand: Pending: *' + pend + '*\n' +
        ':hammer_and_wrench: Dispatched: *' + disp + '*\n' +
        ':white_check_mark: Done: *' + done + '*\n' +
        ':x: Failed: *' + fail + '*\n' +
        'Total: *' + (pend + disp + done + fail) + '*';
    } else {
      const authRes = await httpsRequest(
        pbUrl + '/api/admins/auth-with-password',
        'POST', {}, { identity: 'admin@gostoa.dev', password: pbPass }
      );
      const pbToken = JSON.parse(authRes.data).token;
      const pbAuth = { 'Authorization': 'Bearer ' + pbToken };
      const jobsRes = await httpsRequest(
        pbUrl + '/api/collections/queue_jobs/records?filter=(status=%27pending%27)&sort=priority,created&perPage=10',
        'GET', pbAuth, null
      );
      const jobs = JSON.parse(jobsRes.data).items || [];
      if (jobs.length === 0) {
        responseText = ':inbox_tray: Queue is empty — no pending jobs.';
      } else {
        const lines = jobs.map((j, i) => {
          const score = j.council_score ? ` ${j.council_score}/10` : '';
          const est = j.estimate ? ` ${j.estimate}pts` : '';
          const role = j.role ? ` → ${j.role}` : '';
          const mode = j.mode ? ` ${j.mode}` : '';
          return `${i+1}. *${j.ticket_id}* (P${j.priority}${score}${mode}${est}${role}) — ${j.title || 'untitled'}`;
        });
        responseText = ':inbox_tray: *Next ' + jobs.length + ' Queued Jobs*\n' + lines.join('\n');
      }
    }

  } else {
    responseText = 'Unknown command. Try `/stoa help`.';
  }
} catch (err) {
  responseText = 'Error: ' + err.message;
}

return [{ json: { responseText } }];
